scriptTask.script:

var isValid = true;
var errorMsg = "";

if (!tenantId || tenantId.trim() === "") {
    isValid = false;
    errorMsg += "Tenant ID is required. ";
}

if (!alertData || alertData.trim() === "") {
    isValid = false;
    errorMsg += "Alert data is required. ";
}

if (!priority || priority.trim() === "") {
    isValid = false;
    errorMsg += "Priority is required. ";
}

execution.setVariable("validationResult", isValid);
if (!isValid) {
    execution.setVariable("validationError", errorMsg.trim());
    java.lang.System.out.println("Validation failed: " + errorMsg.trim());
} else {
    java.lang.System.out.println("Data validation completed successfully for tenant: " + tenantId);
}

execution.setVariable("dataValidated", true);


java.lang.System.out.println("Case creation step - Case ID: " + caseId + " for tenant: " + tenantId);
execution.setVariable("caseCreated", true);
execution.setVariable("caseStatus", "DRAFT_00");


java.lang.System.out.println("Creating ATM task for case: " + caseId);
var atmTaskId = "atm-task-" + java.lang.System.currentTimeMillis();
execution.setVariable("atmTaskCreated", true);
execution.setVariable("atmTaskId", atmTaskId);
java.lang.System.out.println("ATM task created with ID: " + atmTaskId);


var atmTaskId = execution.getVariable("atmTaskId");
java.lang.System.out.println("Routing case " + caseId + " to ATM with task " + atmTaskId);

// Get autoclose eligibility from process variables (set by NestJS)
var autocloseEligible = execution.getVariable("autocloseEligible");
if (autocloseEligible === null || autocloseEligible === undefined) {
    // Default logic if not set
    autocloseEligible = (priority === "NEW");
}

execution.setVariable("autocloseEligible", autocloseEligible);
execution.setVariable("routedToATM", true);
java.lang.System.out.println("Case routed to ATM. Autoclose eligible: " + autocloseEligible);


java.lang.System.out.println("Auto-closing case: " + caseId);
execution.setVariable("caseStatus", "AUTOCLOSED");
execution.setVariable("caseClosed", true);
java.lang.System.out.println("Case " + caseId + " has been autoclosed");


java.lang.System.out.println("Creating investigation task for case: " + caseId);
var invTaskId = "inv-task-" + java.lang.System.currentTimeMillis();
execution.setVariable("investigationTaskCreated", true);
execution.setVariable("investigationTaskId", invTaskId);
execution.setVariable("caseStatus", "READY_FOR_ASSIGNMENT");
java.lang.System.out.println("Investigation task created with ID: " + invTaskId);


var caseClosed = execution.getVariable("caseClosed");
var caseStatus = execution.getVariable("caseStatus");
java.lang.System.out.println("Logging case creation for case: " + caseId);
java.lang.System.out.println("Tenant: " + tenantId);
java.lang.System.out.println("Final status: " + caseStatus);
java.lang.System.out.println("Case closed: " + (caseClosed !== null ? caseClosed : false));
execution.setVariable("caseLogged", true);
execution.setVariable("workflowCompleted", true);
